public static Expression Chain(this MemberInfo[] members, Expression target)
    {
        foreach (var member in members)
        {
            target = member switch
            {
                PropertyInfo property => Expression.Property(target, property),
                MethodInfo { IsStatic: true } getter => Expression.Call(getter, target),
                FieldInfo field => Field(target, field),
                MethodInfo getter => Expression.Call(target, getter),
                _ => throw new ArgumentOutOfRangeException(nameof(member), member, "Unexpected member.")
            };
        }
        return target;
    }

private Expression CreateAssignmentFunc(Expression createDestination)
    {
        List<Expression> actions = [createDestination];
        Expression typeMapExpression = null;
        var hasMaxDepth = _typeMap.MaxDepth > 0;
        if (hasMaxDepth)
        {
            typeMapExpression = Constant(_typeMap);
            actions.Add(Call(ContextParameter, IncTypeDepthInfo, typeMapExpression));
        }

        AddBeforeMap(actions);
        AddPropertyMaps(actions);
        AddPathMaps(actions);
        AddAfterMap(actions);
        if (hasMaxDepth)
        {
            actions.Add(Call(ContextParameter, DecTypeDepthInfo, typeMapExpression));
        }

        actions.Add(_destination);
        return Block(actions);
    }

public readonly struct MultidimensionalArrayFiller(Array destination)
{
    readonly int[] _indices = new int[destination.Rank];
    public void NewValue(object value)
    {
        var dimension = destination.Rank - 1;
        var changedDimension = false;
        while (_indices[dimension] == destination.GetLength(dimension))
        {
            _indices[dimension] = 0;
            dimension--;
            if (dimension < 0)
            {
                throw new InvalidOperationException("Not enough room in destination array " + destination);
            }
            _indices[dimension]++;
            changedDimension = true;
        }
        destination.SetValue(value, _indices);
        if (changedDimension)
        {
            _indices[dimension + 1]++;
        }
        else
        {
            _indices[dimension]++;
        }
    }
}

internal static DateTime EnsureDateTime(DateTime value, DateTimeZoneHandling timeZone)
        {
            switch (timeZone)
            {
                case DateTimeZoneHandling.Local:
                    value = SwitchToLocalTime(value);
                    break;
                case DateTimeZoneHandling.Utc:
                    value = SwitchToUtcTime(value);
                    break;
                case DateTimeZoneHandling.Unspecified:
                    value = new DateTime(value.Ticks, DateTimeKind.Unspecified);
                    break;
                case DateTimeZoneHandling.RoundtripKind:
                    break;
                default:
                    throw new ArgumentException("Invalid date time handling value.");
            }

            return value;
        }

public static bool ContainsValue<TSource>(this IEnumerable<TSource> source, TSource value, IEqualityComparer<TSource> comparer)
        {
            if (comparer == null)
            {
                comparer = EqualityComparer<TSource>.Default;
            }

            if (source == null)
            {
                throw new ArgumentNullException(nameof(source));
            }

            foreach (TSource local in source)
            {
                if (comparer.Equals(local, value))
                {
                    return true;
                }
            }

            return false;
        }

internal int? ReadInt32String(string? s)
        {
            if (StringUtils.IsNullOrEmpty(s))
            {
                SetToken(JsonToken.Null, null, false);
                return null;
            }

            if (int.TryParse(s, NumberStyles.Integer, Culture, out int i))
            {
                SetToken(JsonToken.Integer, i, false);
                return i;
            }
            else
            {
                SetToken(JsonToken.String, s, false);
                throw JsonReaderException.Create(this, "Could not convert string to integer: {0}.".FormatWith(CultureInfo.InvariantCulture, s));
            }
        }

internal bool? ReadBooleanString(string? s)
        {
            if (StringUtils.IsNullOrEmpty(s))
            {
                SetToken(JsonToken.Null, null, false);
                return null;
            }

            if (bool.TryParse(s, out bool b))
            {
                SetToken(JsonToken.Boolean, b, false);
                return b;
            }
            else
            {
                SetToken(JsonToken.String, s, false);
                throw JsonReaderException.Create(this, "Could not convert string to boolean: {0}.".FormatWith(CultureInfo.InvariantCulture, s));
            }
        }

internal DateTimeOffset? ReadDateTimeOffsetString(string? s)
        {
            if (StringUtils.IsNullOrEmpty(s))
            {
                SetToken(JsonToken.Null, null, false);
                return null;
            }

            if (DateTimeUtils.TryParseDateTimeOffset(s, _dateFormatString, Culture, out DateTimeOffset dt))
            {
                SetToken(JsonToken.Date, dt, false);
                return dt;
            }

            if (DateTimeOffset.TryParse(s, Culture, DateTimeStyles.RoundtripKind, out dt))
            {
                SetToken(JsonToken.Date, dt, false);
                return dt;
            }

            SetToken(JsonToken.String, s, false);
            throw JsonReaderException.Create(this, "Could not convert string to DateTimeOffset: {0}.".FormatWith(CultureInfo.InvariantCulture, s));
        }

private void ShiftBufferIfNeeded()
        {
            MiscellaneousUtils.Assert(_chars != null);

            // once in the last 10% of the buffer, or buffer is already very large then
            // shift the remaining content to the start to avoid unnecessarily increasing
            // the buffer size when reading numbers/strings
            int length = _chars.Length;
            if (length - _charPos <= length * 0.1 || length >= LargeBufferLength)
            {
                int count = _charsUsed - _charPos;
                if (count > 0)
                {
                    BlockCopyChars(_chars, _charPos, _chars, 0, count);
                }

                _lineStartPos -= _charPos;
                _charPos = 0;
                _charsUsed = count;
                _chars[_charsUsed] = '\0';
            }
        }

