public JProperty? Property(string name, StringComparison comparison)
        {
            if (name == null)
            {
                return null;
            }

            if (_properties.TryGetValue(name, out JToken? property))
            {
                return (JProperty)property;
            }

            // test above already uses this comparison so no need to repeat
            if (comparison != StringComparison.Ordinal)
            {
                for (int i = 0; i < _properties.Count; i++)
                {
                    JProperty p = (JProperty)_properties[i];
                    if (string.Equals(p.Name, name, comparison))
                    {
                        return p;
                    }
                }
            }

            return null;
        }

public override void WriteJson(JsonWriter writer, object? value, JsonSerializer serializer)
        {
            if (value == null)
            {
                writer.WriteNull();
                return;
            }

            Enum e = (Enum)value;

            if (!EnumUtils.TryToString(e.GetType(), value, NamingStrategy, out string? enumName))
            {
                if (!AllowIntegerValues)
                {
                    throw JsonSerializationException.Create(null, writer.ContainerPath, "Integer value {0} is not allowed.".FormatWith(CultureInfo.InvariantCulture, e.ToString("D")), null);
                }

                // enum value has no name so write number
                writer.WriteValue(value);
            }
            else
            {
                writer.WriteValue(enumName);
            }
        }

public static TSource[] Acquire<TSource>(this IEnumerable<TSource> source)
            where TSource : IDisposable
        {
            if (source == null) throw new ArgumentNullException(nameof(source));

            var disposables = new List<TSource>();
            try
            {
                disposables.AddRange(source);
                return [..disposables];
            }
            catch
            {
                foreach (var disposable in disposables)
                    disposable.Dispose();
                throw;
            }
        }

public static IEnumerable<TResult> Choose<T, TResult>(this IEnumerable<T> source,
            Func<T, (bool, TResult)> chooser)
        {
            if (source == null) throw new ArgumentNullException(nameof(source));
            if (chooser == null) throw new ArgumentNullException(nameof(chooser));

            return _(source, chooser);

            static IEnumerable<TResult> _(
                IEnumerable<T> source,
                Func<T, (bool, TResult)> chooser)
            {
                foreach (var item in source)
                {
                    var (some, value) = chooser(item);
                    if (some)
                        yield return value;
                }
            }
        }

public static IEnumerable<TSource> TakeUntil<TSource>(this IEnumerable<TSource> source, Func<TSource, bool> predicate)
        {
            if (source == null) throw new ArgumentNullException(nameof(source));
            if (predicate == null) throw new ArgumentNullException(nameof(predicate));

            return _(source, predicate);

            static IEnumerable<TSource> _(IEnumerable<TSource> source, Func<TSource, bool> predicate)
            {
                foreach (var item in source)
                {
                    yield return item;
                    if (predicate(item))
                        yield break;
                }
            }
        }

public static IEnumerable<TSource> SkipUntil<TSource>(this IEnumerable<TSource> source, Func<TSource, bool> predicate)
        {
            if (source == null) throw new ArgumentNullException(nameof(source));
            if (predicate == null) throw new ArgumentNullException(nameof(predicate));

            return _(source, predicate);

            static IEnumerable<TSource> _(IEnumerable<TSource> source, Func<TSource, bool> predicate)
            {
                using var enumerator = source.GetEnumerator();

                do
                {
                    if (!enumerator.MoveNext())
                        yield break;
                }
                while (!predicate(enumerator.Current));

                while (enumerator.MoveNext())
                    yield return enumerator.Current;
            }
        }

public static IEnumerable<T> TraverseBreadthFirst<T>(T root, Func<T, IEnumerable<T>> childrenSelector)
        {
            if (childrenSelector == null) throw new ArgumentNullException(nameof(childrenSelector));

            return _(root, childrenSelector);

            static IEnumerable<T> _(T root, Func<T, IEnumerable<T>> childrenSelector)
            {
                var queue = new Queue<T>();
                queue.Enqueue(root);

                while (queue.Count != 0)
                {
                    var current = queue.Dequeue();
                    yield return current;
                    foreach (var child in childrenSelector(current))
                        queue.Enqueue(child);
                }
            }
        }

protected string RenderLogEvent(Layout? layout, LogEventInfo logEvent)
        {
            if (layout is null || logEvent is null)
                return string.Empty;    // Signal that input was wrong

            if (layout is IStringValueRenderer stringLayout)
            {
                var result = stringLayout.GetFormattedString(logEvent);
                if (result != null)
                    return result;
            }

            if (TryGetCachedValue(layout, logEvent, out var value))
            {
                return value?.ToString() ?? string.Empty;
            }

            using (var localTarget = ReusableLayoutBuilder.Allocate())
            {
                return layout.RenderAllocateBuilder(logEvent, localTarget.Result);
            }
        }

internal void Close()
        {
            lock (SyncRoot)
            {
                LoggingConfiguration = null;

                if (IsInitialized)
                {
                    _isInitialized = false;

                    try
                    {
                        if (_initializeException is null)
                        {
                            // if Init succeeded, call Close()
                            InternalLogger.Debug("{0}: Closing...", this);
                            CloseTarget();
                            InternalLogger.Debug("{0}: Closed.", this);
                        }
                    }
                    catch (Exception exception)
                    {
                        if (ExceptionMustBeRethrown(exception))
                            throw;
                    }
                }
            }
        }

public virtual DateTimeOffset StartTimeUtc
    {
        get => startTimeUtc;

        set
        {
            if (EndTimeUtc.HasValue && EndTimeUtc.Value < value)
            {
                Throw.ArgumentException("End time cannot be before start time");
            }

            if (!HasMillisecondPrecision)
            {
                // round off millisecond...
                startTimeUtc = value.AddMilliseconds(-value.Millisecond);
            }
            else
            {
                startTimeUtc = value;
            }
        }
    }

public override DateTimeOffset? ComputeFirstFireTimeUtc(ICalendar? cal)
    {
        nextFireTimeUtc = StartTimeUtc;

        if (cal is not null)
        {
            while (!cal.IsTimeIncluded(nextFireTimeUtc.GetValueOrDefault()))
            {
                nextFireTimeUtc = GetFireTimeAfter(nextFireTimeUtc);

                if (!nextFireTimeUtc.HasValue)
                {
                    break;
                }

                //avoid infinite loop
                if (nextFireTimeUtc.GetValueOrDefault().Year > TriggerConstants.YearToGiveUpSchedulingAt)
                {
                    return null;
                }
            }
        }

        return nextFireTimeUtc;
    }

private void StoreJobNoLock(IJobDetail job, bool replaceExisting)
    {
        var jobKey = job.Key;

        if (jobsByKey.TryGetValue(jobKey, out var originalJob))
        {
            if (!replaceExisting)
            {
                Throw.ObjectAlreadyExistsException(job);
            }

            // update job detail
            originalJob.JobDetail = job.Clone();
        }
        else
        {
            // get job group
            if (!jobsByGroup.TryGetValue(jobKey.Group, out var grpMap))
            {
                grpMap = new Dictionary<JobKey, JobWrapper>();
                jobsByGroup[jobKey.Group] = grpMap;
            }

            JobWrapper jw = new JobWrapper(job.Clone());

            // add to jobs by group
            grpMap[jobKey] = jw;
            // add to jobs by FQN map
            jobsByKey[jobKey] = jw;
        }
    }

public async ValueTask<bool> RemoveJobs(IReadOnlyCollection<JobKey> jobKeys, CancellationToken cancellationToken = default)
    {
        await lockObject.WaitAsync(cancellationToken).ConfigureAwait(false);
        try
        {
            bool allFound = true;
            foreach (JobKey key in jobKeys)
            {
                allFound = await RemoveJobNoLock(key, cancellationToken).ConfigureAwait(false) && allFound;
            }

            return allFound;
        }
        finally
        {
            lockObject.Release();
        }
    }

private async ValueTask ResumeTriggerNoLock(TriggerKey triggerKey)
    {
        // does the trigger exist?
        if (!triggersByKey.TryGetValue(triggerKey, out var tw))
        {
            return;
        }

        // if the trigger is not paused resuming it does not make sense...
        if (tw.state != InternalTriggerState.Paused &&
            tw.state != InternalTriggerState.PausedAndBlocked)
        {
            return;
        }

        if (blockedJobs.Contains(tw.JobKey))
        {
            tw.state = InternalTriggerState.Blocked;
        }
        else
        {
            tw.state = InternalTriggerState.Waiting;
        }

        await ApplyMisfireNoLock(tw).ConfigureAwait(false);

        if (tw.state == InternalTriggerState.Waiting)
        {
            timeTriggers.Add(tw);
        }
    }

public static bool Equal<T>(IEnumerable<T>? actual, IEnumerable<T>? expected, IEqualityComparer<T> comparer)
    {
        if (actual == null && expected == null)
            return true;
        if (actual == null || expected == null)
            return false;

        using var expectedEnum = expected.GetEnumerator();
        using var actualEnum = actual.GetEnumerator();

        while (true)
        {
            var expectedHasData = expectedEnum.MoveNext();
            var actualHasData = actualEnum.MoveNext();

            if (!expectedHasData && !actualHasData)
                return true;

            if (expectedHasData != actualHasData || !Equal(actualEnum.Current, expectedEnum.Current, comparer))
            {
                return false;
            }
        }
    }

public static bool EqualIgnoreOrder<T>(IEnumerable<T>? actual, IEnumerable<T>? expected, IEqualityComparer<T> comparer)
    {
        if (actual == null && expected == null)
            return true;

        if (actual == null || expected == null)
            return false;

        if (actual is ICollection actualCollection &&
            expected is ICollection collection &&
            actualCollection.Count != collection.Count)
            return false;

        var expectedList = expected.ToList();
        foreach (var actualElement in actual)
        {
            var match = expectedList.FirstOrDefault(x => Equal(x, actualElement, comparer));
            if (!expectedList.Remove(match!)) // List<T>.Remove works fine when null is passed.
                return false;
        }

        return !expectedList.Any();
    }

public static (List<ParameterExpression> Variables, List<Expression> Expressions) Scratchpad(this IGlobalConfiguration configuration)
    {
        var variables = configuration?.Variables;
        if (variables == null)
        {
            variables = [];
        }
        else
        {
            variables.Clear();
        }
        var expressions = configuration?.Expressions;
        if (expressions == null)
        {
            expressions = [];
        }
        else
        {
            expressions.Clear();
        }
        return (variables, expressions);
    }

ParameterExpression SetVariables(Expression valueResolver, ParameterExpression resolvedValueVariable,
        Expression mappedMember)
    {
        _expressions.Clear();
        _variables.Clear();
        _variables.Add(resolvedValueVariable);
        _expressions.Add(Assign(resolvedValueVariable, valueResolver));
        ParameterExpression mappedMemberVariable;
        if (mappedMember == resolvedValueVariable)
        {
            mappedMemberVariable = resolvedValueVariable;
        }
        else
        {
            mappedMemberVariable = Variable(mappedMember.Type, "mappedValue");
            _variables.Add(mappedMemberVariable);
            _expressions.Add(Assign(mappedMemberVariable, mappedMember));
        }

        return mappedMemberVariable;
    }

private Expression CreateConstructorParameterExpression(ConstructorParameterMap ctorParamMap)
    {
        var defaultValue = ctorParamMap.DefaultValue(_configuration);
        var customSource = GetCustomSource(ctorParamMap);
        var resolvedExpression = BuildValueResolverFunc(ctorParamMap, customSource, defaultValue);
        var resolvedValue = Variable(resolvedExpression.Type, "resolvedValue");
        var mapMember = MapMember(ctorParamMap, resolvedValue, defaultValue);
        _variables.Clear();
        _variables.Add(resolvedValue);
        _expressions.Clear();
        _expressions.Add(Assign(resolvedValue, resolvedExpression));
        _expressions.Add(mapMember);
        return TryMemberMap(ctorParamMap, Block(_variables, _expressions));
    }

static IEnumerable<TState> ScanImpl<TSource, TState>(IEnumerable<TSource> source,
            Func<TState, TSource, TState> transformation,
            Func<IEnumerator<TSource>, (bool, TState)> seeder)
        {
            using var e = source.GetEnumerator();

            var (seeded, aggregator) = seeder(e);

            if (!seeded)
                yield break;

            yield return aggregator;

            while (e.MoveNext())
            {
                aggregator = transformation(aggregator, e.Current);
                yield return aggregator;
            }
        }

public static IEnumerable<TResult> Generate<TResult>(TResult initial, Func<TResult, TResult> generator)
        {
            if (generator == null) throw new ArgumentNullException(nameof(generator));

            return _(initial, generator);

            static IEnumerable<TResult> _(TResult initial, Func<TResult, TResult> generator)
            {
                var current = initial;
                while (true)
                {
                    yield return current;
                    current = generator(current);
                }
            }
        }

public static IEnumerable<T> Pipe<T>(this IEnumerable<T> source, Action<T> action)
        {
            if (source == null) throw new ArgumentNullException(nameof(source));
            if (action == null) throw new ArgumentNullException(nameof(action));

            return _(source, action);

            static IEnumerable<T> _(IEnumerable<T> source, Action<T> action)
            {
                foreach (var element in source)
                {
                    action(element);
                    yield return element;
                }
            }
        }

