static IEnumerable<T> FillForwardImpl<T>(IEnumerable<T> source, Func<T, bool> predicate, Func<T, T, T>? fillSelector)
        {
            (bool, T) seed = default;

            foreach (var item in source)
            {
                if (predicate(item))
                {
                    yield return seed is (true, var theSeed)
                               ? fillSelector != null
                                 ? fillSelector(item, theSeed)
                                 : theSeed
                               : item;
                }
                else
                {
                    seed = (true, item);
                    yield return item;
                }
            }
        }

